 38	export const ReviewAndCreate: React.FC<ReviewAndCreateProps> = ({
 39	  state,
 40	  // any internal or external exists
 41	  hasOCS,
 42	  // both internal and external exists
 43	  hasMultipleClusters,
 44	  supportedExternalStorage,
 45	}) => {
 46	  const { t } = useCustomTranslation();
 47	
 48	  const {
 49	    storageClass,
 50	    capacityAndNodes,
 51	    securityAndNetwork,
 52	    createLocalVolumeSet,
 53	    backingStorage,
 54	    advancedSettings,
 55	    connectionDetails,
 56	    createStorageClass,
 57	    nodes,
 58	  } = state;
 59	  const { capacity, arbiterLocation, enableTaint, enableArbiter } =
 60	    capacityAndNodes;
 61	  const { encryption, kms, networkType } = securityAndNetwork;
 62	  const { deployment, externalStorage, type } = backingStorage;
 63	  const { isDbBackup, enableNFS, isRBDStorageClassDefault } = advancedSettings;
 64	
 65	  // NooBaa standalone deployment
 66	  const isMCG = deployment === DeploymentType.MCG;
 67	  // External Red Hat Ceph Storage deployment
 68	  const isRhcs = !_.isEmpty(connectionDetails);
 69	  // External IBM deployment without ODF
 70	  const isStandaloneExternal = hasOCS && !_.isEmpty(createStorageClass);
 71	
 72	  const isNoProvisioner = storageClass.provisioner === NO_PROVISIONER;
 73	  const formattedCapacity = !isNoProvisioner
 74	    ? `${Number.isFinite(capacity) ? capacity : getStorageSizeInTiBWithoutUnit(capacity as string)} ${StorageSizeUnitName.TiB}`
 75	    : humanizeBinaryBytes(capacity).string;
 76	  const formattedCapacityLimit = formatCapacityText(
 77	    capacityAndNodes.capacityAutoScaling.capacityLimit
 78	  );
 79	
 80	  const hasEncryption = encryption.clusterWide || encryption.storageClass;
 81	  const hasInTransitEncryption = encryption.inTransit
 82	    ? t('Enabled')
 83	    : t('Disabled');
 84	
 85	  const storagePlatform =
 86	    externalStorage &&
 87	    getExternalStorage(externalStorage, supportedExternalStorage).displayName;
 88	
 89	  const encryptionStatus = hasEncryption ? t('Enabled') : t('Disabled');
 90	  const ocsTaintsStatus = enableTaint ? t('Enabled') : t('Disabled');
 91	  const nfsStatus = enableNFS ? t('Enabled') : t('Disabled');
 92	  const isCephRBDSetAsDefault = isRBDStorageClassDefault
 93	    ? t('Enabled')
 94	    : t('Disabled');
 95	  const isDbBackupEnabled = isDbBackup ? t('Enabled') : t('Disabled');
 96	  const isVirtualizeStorageClassDefault =
 97	    advancedSettings.isVirtualizeStorageClassDefault
 98	      ? t('Enabled')
 99	      : t('Disabled');
100	
101	  const kmsStatus = encryption.advanced
102	    ? kms.providerState.name.value
103	    : t('Not connected');
104	
105	  const totalCpu = getTotalCpu(nodes);
106	  const totalMemory = getTotalMemory(nodes);
107	  const zones = getAllZone(nodes);
108	
109	  return (
110	    <>
111	      <ReviewItem title={t('Backing storage')}>
112	        {!isRhcs && !isStandaloneExternal && (
113	          <ListItem>
114	            {t('Deployment type: {{deployment}}', {
115	              deployment,
116	            })}
117	          </ListItem>
118	        )}
119	        {!isRhcs && (
120	          <ListItem>
121	            {t('Backing storage type: {{name}}', {
122	              name: storageClass.name || createLocalVolumeSet.volumeSetName,
123	            })}
124	          </ListItem>
125	        )}
126	        {type === BackingStorageType.EXTERNAL && (
127	          <ListItem>
128	            {t('External storage platform: {{storagePlatform}}', {
129	              storagePlatform,
130	            })}
131	          </ListItem>
132	        )}
133	      </ReviewItem>
134	      <ReviewItem title={t('Advanced settings')}>
135	        {deployment === DeploymentType.FULL &&
136	          type !== BackingStorageType.EXTERNAL && (
137	            <ListItem>
138	              {t('Network file system: {{nfsStatus}}', {
139	                nfsStatus,
140	              })}
141	            </ListItem>
142	          )}
143	        {deployment === DeploymentType.FULL && !hasMultipleClusters && (
144	          <>
145	            <ListItem>
146	              {t(
147	                'Ceph RBD as the default StorageClass: {{isCephRBDSetAsDefault}}',
148	                {
149	                  isCephRBDSetAsDefault,
150	                }
151	              )}
152	            </ListItem>
153	            <ListItem>
154	              {t(
155	                'Default StorageClass for virtualization : {{isVirtualizeStorageClassDefault}}',
156	                {
157	                  isVirtualizeStorageClassDefault,
158	                }
159	              )}
160	            </ListItem>
161	          </>
162	        )}
163	        {isDbBackup && (
164	          <ListItem>
165	            {t('Automatic backup: {{isDbBackupEnabled}}', {
166	              isDbBackupEnabled,
167	            })}
168	          </ListItem>
169	        )}
170	      </ReviewItem>
171	      {!isMCG && !isRhcs && !isStandaloneExternal && (
172	        <ReviewItem title={t('Capacity and nodes')}>
173	          <ListItem>
174	            {t('Cluster capacity: {{capacity}}', {
175	              capacity: formattedCapacity,
176	            })}
177	          </ListItem>
178	          <ListItem>
179	            {t('Selected nodes: {{nodeCount, number}} node', {
180	              nodeCount: nodes.length,
181	              count: nodes.length,
182	            })}
183	          </ListItem>
184	          <ListItem>
185	            {t('CPU and memory: {{cpu, number}} CPU and {{memory}} memory', {
186	              cpu: totalCpu,
187	              memory: humanizeBinaryBytes(totalMemory).string,
188	            })}
189	          </ListItem>
190	          <ListItem>
191	            {t('Performance profile: {{resourceProfile}}', {
192	              resourceProfile: _.capitalize(capacityAndNodes.resourceProfile),
193	            })}
194	          </ListItem>
195	          <ListItem>
196	            {t('Automatic capacity scaling: {{autoscaling}}', {
197	              autoscaling: capacityAndNodes.capacityAutoScaling.enable
198	                ? 'Enabled'
199	                : 'Disabled',
200	            })}
201	            {capacityAndNodes.capacityAutoScaling.enable && (
202	              <ListItem>
203	                {t('Scaling capacity limit: {{capacityLimit}}', {
204	                  capacityLimit: formattedCapacityLimit,
205	                })}
206	              </ListItem>
207	            )}
208	          </ListItem>
209	          <ListItem>
210	            {t('Zone: {{zoneCount, number}} zone', {
211	              zoneCount: zones.size,
212	              count: zones.size,
213	            })}
214	          </ListItem>
215	          {enableArbiter && (
216	            <ListItem>
217	              {t('Arbiter zone: {{zone}}', {
218	                zone: arbiterLocation,
219	              })}
220	            </ListItem>
221	          )}
222	          <ListItem>
223	            {t('Taint nodes: {{ocsTaintsStatus}}', {
224	              ocsTaintsStatus,
225	            })}
226	          </ListItem>
227	        </ReviewItem>
228	      )}
229	      {!isRhcs &&
230	        !isStandaloneExternal &&
231	        (isMCG ? (
232	          <ReviewItem title={t('Security')}>
233	            <ListItem>{t('Encryption: Enabled')}</ListItem>
234	            <ListItem>
235	              {t('External key management service: {{kmsStatus}}', {
236	                kmsStatus,
237	              })}
238	            </ListItem>
239	          </ReviewItem>
240	        ) : (
241	          <ReviewItem title={t('Security and network')}>
242	            <ListItem>
243	              {t('Encryption: {{encryptionStatus}}', { encryptionStatus })}
244	            </ListItem>
245	            <ListItem>
246	              {t('In-transit encryption: {{hasInTransitEncryption}}', {
247	                hasInTransitEncryption,
248	              })}
249	            </ListItem>
250	            {hasEncryption && (
251	              <ListItem>
252	                {t('External key management service: {{kmsStatus}}', {
253	                  kmsStatus,
254	                })}
255	              </ListItem>
256	            )}
257	            <ListItem>
258	              {t('Network: {{networkType}}', {
259	                networkType: NetworkTypeLabels[networkType],
260	              })}
261	            </ListItem>
262	          </ReviewItem>
263	        ))}
264	      {isRhcs && (
265	        <ReviewItem title={t('Security and network')}>
266	          <ListItem>
267	            {t('In-transit encryption: {{hasInTransitEncryption}}', {
268	              hasInTransitEncryption,
269	            })}
270	          </ListItem>
271	        </ReviewItem>
272	      )}
273	    </>
274	  );
275	};
